#!/usr/bin/env python3
"""Utility-greedy + BFS exploration planner for cogniplan_env."""
import os, sys, json, argparse, math, random
from collections import deque
import numpy as np
from cogniplan_env import ExplorationEnv

CELL_SIZE = 0.4
SUCCESS_THRESHOLD = 0.9999
MAX_STEPS = 128

def euclidean(a, b):
    return math.hypot(a[0]-b[0], a[1]-b[1])

def round_key(coord, decimals=3):
    return (round(coord[0], decimals), round(coord[1], decimals))

class UtilityGreedyPlanner:
    def __init__(self, eps=0.0):
        self.eps = eps

    def _set_graph(self, nodes):
        n = len(nodes)
        self.nodes_coords = []
        self.coord_to_idx = {}
        for i, nd in enumerate(nodes):
            coords = (float(nd['coords'][0]), float(nd['coords'][1]))
            rk = round_key(coords)
            self.nodes_coords.append(rk)
            self.coord_to_idx[rk] = i
        self.adj = [[] for _ in range(n)]
        for i, nd in enumerate(nodes):
            for nb in nd.get('neighbors', []):
                nb_coords = (float(nb[0]), float(nb[1]))
                j = self.coord_to_idx.get(round_key(nb_coords), -1)
                if j >= 0 and j != i:
                    if j not in self.adj[i]:
                        self.adj[i].append(j)
                    if i not in self.adj[j]:
                        self.adj[j].append(i)
        self.n_nodes = n

    def get_closest_node_idx(self, pos):
        best_idx = 0
        best_d = float('inf')
        for i, coord in enumerate(self.nodes_coords):
            d = euclidean(pos, coord)
            if d < best_d:
                best_d = d
                best_idx = i
        return best_idx

    def bfs_path(self, start_idx, goal_idx):
        if start_idx == goal_idx:
            return []
        n = self.n_nodes
        parent = [-1] * n
        seen = [False] * n
        seen[start_idx] = True
        q = deque([start_idx])
        while q:
            u = q.popleft()
            if u == goal_idx:
                break
            for v in self.adj[u]:
                if not seen[v]:
                    seen[v] = True
                    parent[v] = u
                    q.append(v)
        if not seen[goal_idx]:
            return []
        path = []
        cur = goal_idx
        while cur != start_idx:
            path.append(cur)
            cur = parent[cur]
        path.reverse()
        return path

    def select_action(self, obs, curr_idx, tabu):
        nodes = obs['nodes']
        neighbors = obs['neighbors']
        # Local greedy among neighbors
        candidates = []
        for nb_coords in neighbors:
            nb_key = round_key((float(nb_coords[0]), float(nb_coords[1])))
            nb_idx = self.coord_to_idx.get(nb_key, -1)
            if nb_idx == -1:
                continue
            if nb_idx in tabu:
                continue
            utility = nodes[nb_idx]['utility']
            candidates.append((utility, nb_idx, nb_coords))
        if candidates:
            max_util = max(c[0] for c in candidates)
            if max_util > 0:
                if random.random() < self.eps:
                    idx = random.randrange(len(candidates))
                    return candidates[idx][2], candidates[idx][1]
                best_utils = [c for c in candidates if c[0] == max_util]
                pos = obs['robot_pos']
                best_utils.sort(key=lambda c: euclidean(pos, (nodes[c[1]]['coords'][0], nodes[c[1]]['coords'][1])))
                return best_utils[0][2], best_utils[0][1]
        # Global BFS to highest utility node (not in tabu)
        global_best_idx = -1
        global_best_util = -1
        for i, nd in enumerate(nodes):
            if i in tabu:
                continue
            u = nd['utility']
            if u > global_best_util:
                global_best_util = u
                global_best_idx = i
        if global_best_util > 0:
            path = self.bfs_path(curr_idx, global_best_idx)
            if path:
                next_idx = path[0]
                target_coords = (nodes[next_idx]['coords'][0], nodes[next_idx]['coords'][1])
                return target_coords, next_idx
        # Fallback: any neighbor not in tabu
        for nb_coords in neighbors:
            nb_key = round_key((float(nb_coords[0]), float(nb_coords[1])))
            nb_idx = self.coord_to_idx.get(nb_key, -1)
            if nb_idx != -1 and nb_idx not in tabu:
                return nb_coords, nb_idx
        # Last resort: first neighbor (ignore tabu)
        if neighbors:
            nb_coords = neighbors[0]
            nb_key = round_key((float(nb_coords[0]), float(nb_coords[1])))
            nb_idx = self.coord_to_idx.get(nb_key, -1)
            if nb_idx != -1:
                return nb_coords, nb_idx
        return None, None

def run_episode(env, planner, max_steps=128):
    obs = env.reset()
    planner._set_graph(obs['nodes'])
    curr_idx = planner.get_closest_node_idx(obs['robot_pos'])
    tabu = deque(maxlen=3)  # short memory to prevent immediate backtrack
    for step in range(max_steps):
        target, next_idx = planner.select_action(obs, curr_idx, set(tabu))
        if target is None:
            break
        obs, info = env.step(target)
        if info['done']:
            break
        # rebuild graph with new nodes, update position
        planner._set_graph(obs['nodes'])
        curr_idx = planner.get_closest_node_idx(obs['robot_pos'])
        tabu.append(next_idx)
    metrics = env.get_metrics()
    return metrics

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    data_dir = args.data_path
    config_path = os.path.join(data_dir, 'eval_config.json')
    with open(config_path, 'r') as f:
        config = json.load(f)

    maps_dir = os.path.join(data_dir, 'maps_eval')
    env_types = ['room', 'tunnel', 'outdoor']

    per_episode = []
    per_type = {t: {'explored_rate': 0.0, 'travel_distance': 0.0, 'success_rate': 0.0, 'n_eps': 0} for t in env_types}

    planner = UtilityGreedyPlanner(eps=0.0)

    for env_type in env_types:
        type_dir = os.path.join(maps_dir, env_type)
        if not os.path.isdir(type_dir):
            continue
        map_files = sorted([f for f in os.listdir(type_dir) if f.endswith('.png')])
        for map_file in map_files:
            map_path = os.path.join(type_dir, map_file)
            env = ExplorationEnv(map_path=map_path)
            metrics = run_episode(env, planner)
            ep_success = 1 if metrics['success'] else 0
            ep_entry = {
                'map_path': os.path.join(env_type, map_file),
                'env_type': env_type,
                'success': ep_success,
                'travel_distance': metrics['travel_distance'],
                'explored_rate': metrics['explored_rate']
            }
            per_episode.append(ep_entry)
            per_type[env_type]['n_eps'] += 1
            per_type[env_type]['explored_rate'] += metrics['explored_rate']
            if ep_success:
                per_type[env_type]['travel_distance'] += metrics['travel_distance']
                per_type[env_type]['success_rate'] += 1

    total_episodes = len(per_episode)
    overall_explored = sum(ep['explored_rate'] for ep in per_episode) / max(1, total_episodes)
    overall_success = sum(ep['success'] for ep in per_episode) / max(1, total_episodes)
    overall_distance = 0.0
    n_success = sum(ep['success'] for ep in per_episode)
    if n_success > 0:
        overall_distance = sum(ep['travel_distance'] for ep in per_episode if ep['success']) / n_success

    # per_type averages
    for t in env_types:
        n = per_type[t]['n_eps']
        if n > 0:
            per_type[t]['explored_rate'] /= n
            if per_type[t]['success_rate'] > 0:
                per_type[t]['travel_distance'] /= per_type[t]['success_rate']
            per_type[t]['success_rate'] /= n
        else:
            per_type[t] = {'explored_rate': 0.0, 'travel_distance': 0.0, 'success_rate': 0.0}

    output = {
        'explored_rate': overall_explored,
        'travel_distance': overall_distance,
        'success_rate': overall_success,
        'per_episode': per_episode,
        'per_type': per_type,
        'total_episodes': total_episodes
    }

    with open(args.output, 'w') as f:
        json.dump(output, f, indent=2)

if __name__ == '__main__':
    main()
